function formatDateToISO(t){if(!t)return"";const[e,n,r]=t.split("/").map(Number);return new Date(Date.UTC(r,n-1,e)).toISOString()}function formatDate(t){return t?new Date(t).toLocaleDateString("el-GR",{day:"2-digit",month:"2-digit",year:"numeric"}):""}function formatDateRepo_Argies(t){const e=new Date(t);return`${String(e.getUTCDate()).padStart(2,"0")}/${String(e.getUTCMonth()+1).padStart(2,"0")}/${e.getUTCFullYear()}`}function formatDateToYYYY_MM_DD(t){const e=new Date(t),n=String(e.getUTCDate()).padStart(2,"0"),r=String(e.getUTCMonth()+1).padStart(2,"0");return`${e.getUTCFullYear()}-${r}-${n}`}function formatDateToCustom(t){return date=new Date(t),`${date.getUTCFullYear()}-${String(date.getMonth()+1).padStart(2,"0")}-${String(date.getDate()).padStart(2,"0")}T00:00:00.000Z`}function parseDateDDMMYYYY(t){if(!t)return null;const[e,n,r]=t.split("/");return new Date(Number(r),Number(n)-1,Number(e))}function detectDateFormat(t){return t instanceof Date?"DateObject":"string"!=typeof t?null:/^\d{2}\/\d{2}\/\d{4}$/.test(t)?"DD/MM/YYYY":/^\d{4}-\d{2}-\d{2}$/.test(t)?"YYYY-MM-DD":null}function formatDateRepoArgies(t){const e=detectDateFormat(t);return"DateObject"===e?t.toLocaleDateString("el-GR"):"YYYY-MM-DD"===e?t.split("-").reverse().join("/"):"DD/MM/YYYY"===e?t:void 0}function isLeapYear(t){return t%4==0&&(t%100!=0||t%400==0)}